function validateDamages(damages: { itemType: string }[], policyItems: Item[]): void {
  for (const damage of damages) {
    if (!policyItems.some((item) => item.type === damage.itemType)) {
      fail(`Damaged item type not in policy: ${damage.itemType}`);
    }
  }
  const damageCounts = new Map<string, number>();
  for (const damage of damages) {
    damageCounts.set(damage.itemType, (damageCounts.get(damage.itemType) ?? 0) + 1);
  }
  const policyCounts = new Map<string, number>();
  for (const item of policyItems) {
    policyCounts.set(item.type, (policyCounts.get(item.type) ?? 0) + 1);
  }
  for (const [itemType, count] of damageCounts) {
    if (count > (policyCounts.get(itemType) ?? 0)) {
      fail(`More damages of type ${itemType} than policy covers`);
    }
  }
}
